#include &lt;Arduino.h&gt;
#include &lt;U8g2lib.h&gt;
#include &lt;Wire.h&gt;
#include &lt;Adafruit_BME680.h&gt;

#define YELLOW_LED 25
#define RED_LED    26
#define WHITE_LED   2

// Inland IIC SPI 1.3" 128x64 OLED V2.0 Graphic Display Module SPI wiring
// CLK = 18, MOSI = 23, CS = 5, DC = 12, RES = 4
U8G2_SH1106_128X64_NONAME_F_4W_HW_SPI u8g2(
  U8G2_R0,
  /* cs=*/ 5,
  /* dc=*/ 12,
  /* reset=*/ 4
);

Adafruit_BME680 bme;

void drawTemperature(float tempC) {
  u8g2.clearBuffer();
  u8g2.setFont(u8g2_font_ncenB08_tr);
  u8g2.drawStr(10, 15, "Temperature");

  char tempStr[20];
  snprintf(tempStr, sizeof(tempStr), "%.2f C", tempC);

  u8g2.setFont(u8g2_font_logisoso20_tr);
  u8g2.drawStr(10, 45, tempStr);
  u8g2.sendBuffer();
}

void drawSmiley() {
  u8g2.clearBuffer();

  // Face outline
  u8g2.drawCircle(64, 32, 22);

  // Eyes
  u8g2.drawDisc(56, 26, 2);
  u8g2.drawDisc(72, 26, 2);

  // Smile
  u8g2.drawArc(64, 34, 10, 8, 200, 340);

  u8g2.sendBuffer();
}

void drawTitle() {
  u8g2.clearBuffer();
  u8g2.setFont(u8g2_font_ncenB08_tr);
  u8g2.drawStr(10, 22, "Rick's Weather");
  u8g2.drawStr(28, 42, "Station");
  u8g2.sendBuffer();
}

void flashLEDs() {
  for (int i = 0; i &lt; 3; i++) {
    digitalWrite(RED_LED, HIGH);
    digitalWrite(YELLOW_LED, LOW);
    digitalWrite(WHITE_LED, LOW);
    delay(300);

    digitalWrite(RED_LED, LOW);
    digitalWrite(YELLOW_LED, HIGH);
    digitalWrite(WHITE_LED, LOW);
    delay(300);

    digitalWrite(RED_LED, LOW);
    digitalWrite(YELLOW_LED, LOW);
    digitalWrite(WHITE_LED, HIGH);
    delay(300);
  }

  digitalWrite(RED_LED, LOW);
  digitalWrite(YELLOW_LED, LOW);
  digitalWrite(WHITE_LED, LOW);
}

void setup() {
  Serial.begin(115200);
  delay(500);
  Serial.println("Rick's Weather Station Starting...");

  pinMode(RED_LED, OUTPUT);
  pinMode(YELLOW_LED, OUTPUT);
  pinMode(WHITE_LED, OUTPUT);

  digitalWrite(RED_LED, LOW);
  digitalWrite(YELLOW_LED, LOW);
  digitalWrite(WHITE_LED, LOW);

  u8g2.begin();

  Wire.begin(21, 22);

  if (!bme.begin(0x77)) {
    Serial.println("Could not find BME680 sensor!");
    while (1);
  }

  bme.setTemperatureOversampling(BME680_OS_8X);
  bme.setHumidityOversampling(BME680_OS_2X);
  bme.setPressureOversampling(BME680_OS_4X);
  bme.setIIRFilterSize(BME680_FILTER_SIZE_3);

  Serial.println("BME680 initialized successfully.");
}

void loop() {
  if (!bme.performReading()) {
    Serial.println("Failed to read from BME680");
    delay(1000);
    return;
  }

  float temperatureC = bme.temperature;
  Serial.print("Temperature: ");
  Serial.print(temperatureC);
  Serial.println(" C");

  // Step 1: Display temperature
  drawTemperature(temperatureC);
  delay(2000);

  // Step 2: Show smiley
  drawSmiley();
  delay(1500);

  // Step 3: Show title
  drawTitle();
  delay(2000);

  // Step 4: Flash LEDs
  flashLEDs();

  delay(1000);
}

Functions offered by Micro-controller:

Core Control function: Adjust mode control, Inverter Compressor Speed, Voltage Range
User UI functions: Mode, Temperature, Timer, Sleep, Turbo Control
Smart Features: Vertical, Horizontal Swing, LCD display
Safety Features: Compressor Protection Algorithm, Voltage Fluctuation, Anti-Freeze
Energy Management: Stop/Start to save power, Energy efficiency optimization


